# ── .cyc 바이너리 파서 유틸리티 (PNE .cyc → Cycleraw 재구성) ──────────

# .cyc 헤더 오프셋 상수
_CYC_HDR_N_FIELDS = 0x148   # uint32 LE: 필드 수
_CYC_HDR_FIDS     = 0x14C   # uint16 LE × n_fields: FieldID 배열
_CYC_DATA_START   = 0x1B0   # 데이터 시작 오프셋 (고정)


def _parse_cyc_header(cyc_path: str) -> dict:
    """CYC 바이너리 파일 헤더 파싱.

    Returns
    -------
    dict
        n_fields, fids, data_start, rec_size, total_records
    """
    file_size = os.path.getsize(cyc_path)
    with open(cyc_path, 'rb') as f:
        f.seek(_CYC_HDR_N_FIELDS)
        n_fields = struct.unpack('<I', f.read(4))[0]
        f.seek(_CYC_HDR_FIDS)
        fids = list(struct.unpack(f'<{n_fields}H', f.read(n_fields * 2)))
    rec_size = n_fields * 4
    total_records = (file_size - _CYC_DATA_START) // rec_size
    return {
        'n_fields': n_fields, 'fids': fids,
        'data_start': _CYC_DATA_START,
        'rec_size': rec_size, 'total_records': total_records,
    }


def _read_cyc_records(cyc_path: str, start: int = 0,
                      count: int | None = None) -> np.ndarray:
    """CYC 레코드를 numpy float32 배열로 로딩.

    Returns
    -------
    np.ndarray
        shape (N, n_fields) float32
    """
    hdr = _parse_cyc_header(cyc_path)
    n_fields = hdr['n_fields']
    data_start = hdr['data_start']
    rec_size = hdr['rec_size']
    total = hdr['total_records']
    if count is None:
        count = total - start
    with open(cyc_path, 'rb') as f:
        f.seek(data_start + start * rec_size)
        raw = f.read(count * rec_size)
    return np.frombuffer(raw, dtype='<f4').reshape(count, n_fields)


def _build_fid_pos(fids: list[int]) -> dict[int, int]:
    """FieldID → 레코드 내 float32 인덱스 매핑 (첫 등장 우선)."""
    pos = {}
    for i, fid in enumerate(fids):
        if fid not in pos:
            pos[fid] = i
    return pos


def _cyc_supplement_profile_info(cyc_path: str, cyc_df: pd.DataFrame,
                                 supplement: pd.DataFrame) -> dict:
    """보충 구간의 프로파일 행수 및 기록시각(FID 43/44) 추정.

    Parameters
    ----------
    cyc_path : str
        .cyc 파일 경로.
    cyc_df : pd.DataFrame
        _cyc_to_cycle_df 결과 (RecIndex + TotlCycle 등).
    supplement : pd.DataFrame
        SaveEndData 포맷으로 변환된 보충 메타 행들 (col[0]=RecIdx,
        col[27]=TotlCycle).

    Returns
    -------
    dict
        {"steps": ", 프로파일 NNN행" | "", "profile": ...(구버전 호환 빈값),
         "time": " [YYYY-MM-DD HH:MM:SS ~ ... (N.NNh)]" | ""}
        실패 시 각 필드 빈 문자열.
    """
    empty = {"steps": "", "profile": "", "time": ""}
    try:
        if supplement is None or supplement.empty:
            return empty

        # 보충된 스텝들의 RecIndex 범위 (= 프로파일 시계열 레코드 범위)
        rec_indices = supplement[0].astype(int).tolist()
        last_recidx = max(rec_indices)
        # 첫 보충 스텝의 시작 RecIndex를 _build_step_meta_from_cyc_df로 역산
        try:
            step_meta = _build_step_meta_from_cyc_df(cyc_df)
            cyc_rec_to_pos = {int(r): i for i, r in enumerate(
                cyc_df['RecIndex'].tolist())}
            # supplement의 가장 이른 RecIndex에 해당하는 cyc_df 위치
            first_recidx_in_supp = min(rec_indices)
            pos = cyc_rec_to_pos.get(first_recidx_in_supp)
            if pos is not None:
                first_recidx = int(step_meta[pos, 0])   # 해당 스텝의 start_idx
            else:
                first_recidx = first_recidx_in_supp
        except Exception:
            first_recidx = min(rec_indices)

        profile_rows = max(0, last_recidx - first_recidx + 1)
        steps_str = ""  # 별도 항목 필요 시 추가 가능
        profile_str = (f', 프로파일 {profile_rows}행'
                       if profile_rows > 0 else '')

        # 기록시각: FID 43(YYMMDD) + FID 44(HHMMSSmmm)
        time_str = ""
        try:
            hdr = _parse_cyc_header(cyc_path)
            fp = _build_fid_pos(hdr['fids'])
            if 43 in fp and 44 in fp:
                first_rec = _read_cyc_records(cyc_path, first_recidx - 1, 1)
                last_rec = _read_cyc_records(cyc_path, last_recidx - 1, 1)
                if len(first_rec) and len(last_rec):
                    from datetime import datetime as _dt

                    def _parse_dt(rec):
                        d = int(rec[0, fp[43]])
                        t = int(rec[0, fp[44]])
                        return _dt(
                            2000 + d // 10000, (d // 100) % 100, d % 100,
                            t // 10000000, (t // 100000) % 100,
                            (t // 1000) % 100, (t % 1000) * 1000)

                    start_dt = _parse_dt(first_rec)
                    end_dt = _parse_dt(last_rec)
                    dur_h = (end_dt - start_dt).total_seconds() / 3600
                    time_str = (f"  [{start_dt.strftime('%Y-%m-%d %H:%M:%S')}"
                                f" ~ {end_dt.strftime('%Y-%m-%d %H:%M:%S')}"
                                f" ({dur_h:.2f}h)]")
        except Exception:
            time_str = ""

        return {"steps": steps_str, "profile": profile_str, "time": time_str}
    except Exception:
        return empty


def _detect_cyc_loop_markers(
    data: "np.ndarray", p_time: int, jump_threshold: float = 300.0,
) -> set:
    """.cyc 레코드 배열에서 LOOP 마커 스텝 마지막 레코드 인덱스 반환.

    Tier 2 규칙 (tools/tc_rebuilder.py 참조):
        스텝 경계(StepTime=0) 사이에서 마지막 레코드의 StepTime이 그 전
        레코드 대비 jump_threshold초(기본 300s) 이상 점프하면 LOOP 마커.

    실측 검증 (2026-04-18, 15 채널):
        Precision 98.67%, Recall 98.89%.
        cond_b 보조(main_curr<20 + main_dmed==0 + last_d>100)는 호출측에
        유지되어 짧은 Loop의 엣지 케이스를 보강한다.
    """
    N = len(data)
    if N == 0:
        return set()
    times = data[:, p_time]
    starts = np.where(times == 0.0)[0].tolist() + [N]
    result = set()
    for i in range(len(starts) - 1):
        s = int(starts[i])
        e = int(starts[i + 1]) - 1
        if e > s and float(times[e]) - float(times[e - 1]) > jump_threshold:
            result.add(e)
    return result


def _cyc_to_cycle_df(cyc_path: str) -> pd.DataFrame:
    """CYC 바이너리 → pne_cycle_data Cycleraw 등가 DataFrame 재구성.

    .cyc 파일을 파싱하여 SaveEndData.csv와 동일한 13개 컬럼 DataFrame을 생성.
    imp는 스텝별 시계열에서 10초 DC 내부저항으로 계산 (|V_ocv - V@10s| / |I@10s| × 1e6).

    LOOP 감지 (TC 경계 판별):
        - 주 규칙 (cond_a): _detect_cyc_loop_markers — StepTime 점프 > 300s
          실측 Precision 98.67% / Recall 98.89%
        - 보조 규칙 (cond_b): 짧은 Loop 엣지 케이스 (main_curr<20mA &
          main_dmed==0 & last_d>100mAh)
        - Tier 2 규칙은 SaveEndData col[27]과 대조 시 100% 일치 (PAT_END
          예외 포함) — tools/tc_rebuilder.py rebuild_tc_from_step_sequence 참조

    Parameters
    ----------
    cyc_path : str
        .cyc 파일 경로

    Returns
    -------
    pd.DataFrame
        컬럼: TotlCycle, Condition, chgCap, DchgCap, Ocv, imp, volmax,
              DchgEngD, steptime, Curr, Temp, AvgV, EndState
        단위: CSV SaveEndData와 동일 (uV, uA, uAh, cs, mC, Wh, µΩ)
    """
    hdr = _parse_cyc_header(cyc_path)
    fids = hdr['fids']
    fid_pos = _build_fid_pos(fids)

    _COLS = ["RecIndex", "TotlCycle", "Condition", "chgCap", "DchgCap", "Ocv", "imp",
             "volmax", "DchgEngD", "steptime", "Curr", "Temp", "AvgV", "EndState"]

    data = _read_cyc_records(cyc_path)
    N = len(data)
    if N == 0:
        return pd.DataFrame(columns=_COLS)

    # 필수/옵션 FieldID 인덱스
    p_idx = fid_pos[22]       # Index (레코드 번호)
    p_time = fid_pos[6]       # StepTime (sec)
    p_volt = fid_pos[1]       # 전압 (mV)
    p_curr = fid_pos[2]       # 전류 (mA)
    p_dchg = fid_pos[27]      # 방전용량 (mAh)
    p_chg = fid_pos.get(26)   # 충전용량 (mAh)
    p_temp = fid_pos.get(12)  # Temp1 (°C)
    p_temp4 = fid_pos.get(49) # Temp4 (col[24])
    p_volmax = fid_pos.get(45)  # volmax (uV)
    p_avgv = fid_pos.get(24)    # AvgVolt (mV)
    p_deng = fid_pos.get(35)    # DchgEngD (Wh)

    # Temp4 단위 자동 감지: °C(소수) vs mC(정수)
    _t4_scale = 1000
    if p_temp4 is not None:
        sample = data[:min(200, N), p_temp4]
        nz = sample[sample != 0.0]
        if len(nz) > 0 and abs(float(nz[0])) > 200:
            _t4_scale = 1  # 이미 mC 단위

    fid6 = data[:, p_time]
    step_starts = np.where(fid6 == 0.0)[0].tolist()
    boundaries = step_starts + [N]

    _CC_CV_RATIO = 0.05
    _LOOP_JUMP = 300.0

    # Tier 2 규칙: StepTime 점프 > _LOOP_JUMP 인 스텝 마지막 레코드 = LOOP 마커
    # (사전 계산으로 내부 루프 가독성 향상)
    loop_marker_indices = _detect_cyc_loop_markers(data, p_time, _LOOP_JUMP)

    rows = []
    totl_cycle = 1

    for k in range(len(step_starts)):
        s = boundaries[k]
        e = boundaries[k + 1]
        seg = data[s:e]
        if len(seg) == 0:
            continue
        M = len(seg)
        seg_t = seg[:, p_time]

        # ── 루프 마커 감지 ──
        # cond_a: 스텝 마지막 레코드 StepTime 점프 (Tier 2 주 규칙)
        last_rec_idx = e - 1
        cond_a = last_rec_idx in loop_marker_indices

        # cond_b: 짧은 Loop 엣지 케이스 보조 (main_curr<20 + main_dmed==0 + last_d>100)
        has_loop = cond_a
        if not has_loop and M >= 2:
            main_curr = float(np.mean(np.abs(seg[:-1, p_curr])))
            main_dmed = float(np.median(seg[:-1, p_dchg]))
            last_d = float(seg[-1, p_dchg])
            cond_b = (main_curr < 20.0 and main_dmed == 0.0 and last_d > 100.0)
            has_loop = cond_b

        main_seg = seg[:-1] if has_loop else seg
        loop_rec = seg[-1] if has_loop else None
        if len(main_seg) == 0:
            continue

        last = main_seg[-1]
        n_main = len(main_seg)

        # ── StepType 추론 ──
        mean_c = float(np.mean(main_seg[:, p_curr]))
        if mean_c > 10.0:
            stype = 1   # 충전
        elif mean_c < -10.0:
            stype = 2   # 방전
        else:
            stype = 3   # 휴지

        # ── EndState 추론 (CC/CV 상대 변동률 기반) ──
        tail_n = max(n_main // 3, min(n_main, 3))
        tail_c = main_seg[-tail_n:, p_curr]
        t_std = float(np.std(tail_c))
        t_abs = float(np.mean(np.abs(tail_c)))
        if stype in (1, 2):
            es = 66 if t_std / max(t_abs, 1.0) > _CC_CV_RATIO else 65
        else:
            es = 64

        # ── imp 계산 (충방전 스텝, 10초 DC 내부저항) ──
        imp_val = 0
        if stype in (1, 2) and n_main >= 2:
            v_ocv = float(main_seg[0, p_volt])  # mV
            times = main_seg[:, p_time]
            idx10 = int(np.searchsorted(times, 10.0))
            if idx10 < n_main:
                t_act = float(times[idx10])
                if abs(t_act - 10.0) <= 2.0:
                    v10 = float(main_seg[idx10, p_volt])
                    i10 = float(main_seg[idx10, p_curr])
                    if abs(i10) > 0.1:
                        imp_val = int(abs(v_ocv - v10) / abs(i10) * 1e6)

        # ── 값 추출 (CSV 단위 변환 적용) ──
        volt_uv = int(float(last[p_volt]) * 1000)
        curr_ua = int(float(last[p_curr]) * 1000)
        dchg_uah = int(float(last[p_dchg]) * 1000)
        chg_uah = int(float(last[p_chg]) * 1000) if p_chg is not None else 0
        time_cs = int(round(float(last[p_time]) * 100))
        if p_temp4 is not None:
            temp_mc = int(float(last[p_temp4]) * _t4_scale)
        elif p_temp is not None:
            temp_mc = int(float(last[p_temp]) * 1000)
        else:
            temp_mc = 0
        vmax = int(float(last[p_volmax])) if p_volmax is not None else 0
        avgv = int(float(last[p_avgv]) * 1000) if p_avgv is not None else 0
        deng = float(last[p_deng]) if p_deng is not None else 0.0

        rec_index = int(float(last[p_idx]))
        rows.append({
            'RecIndex': rec_index,
            'TotlCycle': totl_cycle, 'Condition': stype,
            'chgCap': chg_uah, 'DchgCap': dchg_uah,
            'Ocv': volt_uv, 'imp': imp_val,
            'volmax': vmax, 'DchgEngD': deng,
            'steptime': time_cs, 'Curr': curr_ua,
            'Temp': temp_mc, 'AvgV': avgv, 'EndState': es,
        })

        # ── 루프 마커 ──
        if has_loop and loop_rec is not None:
            lr = loop_rec
            lv = int(float(lr[p_volt]) * 1000)
            li = int(float(lr[p_curr]) * 1000)
            ld = int(float(lr[p_dchg]) * 1000)
            lch = int(float(lr[p_chg]) * 1000) if p_chg is not None else 0
            lt = int(round(float(lr[p_time]) * 100))
            if p_temp4 is not None:
                ltemp = int(float(lr[p_temp4]) * _t4_scale)
            elif p_temp is not None:
                ltemp = int(float(lr[p_temp]) * 1000)
            else:
                ltemp = 0
            lvmax = int(float(lr[p_volmax])) if p_volmax is not None else 0
            lavg = int(float(lr[p_avgv]) * 1000) if p_avgv is not None else 0
            ldeng = float(lr[p_deng]) if p_deng is not None else 0.0

            loop_index = int(float(lr[p_idx]))
            rows.append({
                'RecIndex': loop_index,
                'TotlCycle': totl_cycle, 'Condition': 8,
                'chgCap': lch, 'DchgCap': ld,
                'Ocv': lv, 'imp': 0,
                'volmax': lvmax, 'DchgEngD': ldeng,
                'steptime': lt, 'Curr': li,
                'Temp': ltemp, 'AvgV': lavg, 'EndState': 64,
            })
            totl_cycle += 1

    return pd.DataFrame(rows, columns=_COLS)


def _cyc_df_to_save_end_format(cyc_df: pd.DataFrame, n_cols: int = 48) -> pd.DataFrame:
    """_cyc_to_cycle_df의 13컬럼 결과를 SaveEndData.csv 컬럼 형식으로 역매핑.

    SaveEndData의 컬럼 인덱스에 .cyc 값을 배치하여 pne_search_cycle 등과 호환.
    매핑되지 않는 컬럼은 0으로 채움.

    Parameters
    ----------
    cyc_df : pd.DataFrame
        _cyc_to_cycle_df 반환값 (13컬럼: TotlCycle, Condition, ...)
    n_cols : int
        SaveEndData 컬럼 수 (기본 48)

    Returns
    -------
    pd.DataFrame
        int 인덱스 컬럼 (0 ~ n_cols-1), SaveEndData.csv와 동일 구조
    """
    # SaveEndData 컬럼 인덱스 ↔ cyc_df 컬럼명 매핑
    # pne_cycle_data: save_end_cached[[27,2,10,11,8,20,45,15,17,9,24,29,6]]
    _SAVE_END_MAP = {
        0: 'RecIndex',
        27: 'TotlCycle', 2: 'Condition', 10: 'chgCap', 11: 'DchgCap',
        8: 'Ocv', 20: 'imp', 45: 'volmax', 15: 'DchgEngD',
        17: 'steptime', 9: 'Curr', 24: 'Temp', 29: 'AvgV', 6: 'EndState',
    }
    result = pd.DataFrame(0, index=range(len(cyc_df)), columns=range(n_cols))
    for se_col, cyc_col in _SAVE_END_MAP.items():
        if cyc_col in cyc_df.columns and se_col < n_cols:
            result[se_col] = cyc_df[cyc_col].values
    return result


