class BorderDelegate(QtWidgets.QStyledItemDelegate):
    """셀 배경을 둥근 모서리로 그리고, UserRole+100에 QColor가 설정되면 테두리 표시."""
    BORDER_ROLE = QtCore.Qt.ItemDataRole.UserRole + 100
    _RADIUS = 6  # 모서리 둥글기 (px)
    _MARGIN = 1  # 셀 안쪽 여백 (px)

    def paint(self, painter, option, index):
        painter.save()
        painter.setRenderHint(QtGui.QPainter.RenderHint.Antialiasing, True)

        # 둥근 배경 영역
        rect = option.rect.adjusted(self._MARGIN, self._MARGIN,
                                    -self._MARGIN, -self._MARGIN)

        # 배경색 결정 (선택 상태 / 아이템 배경색 / 기본)
        if option.state & QtWidgets.QStyle.StateFlag.State_Selected:
            bg = option.palette.highlight().color()
        else:
            bg_brush = index.data(QtCore.Qt.ItemDataRole.BackgroundRole)
            if bg_brush and isinstance(bg_brush, QtGui.QBrush):
                bg = bg_brush.color()
            elif bg_brush and isinstance(bg_brush, QtGui.QColor):
                bg = bg_brush
            else:
                bg = option.palette.base().color()

        # 둥근 사각형으로 배경 칠하기
        painter.setPen(QtCore.Qt.PenStyle.NoPen)
        painter.setBrush(bg)
        painter.drawRoundedRect(QtCore.QRectF(rect), self._RADIUS, self._RADIUS)

        # 텍스트 그리기
        text = index.data(QtCore.Qt.ItemDataRole.DisplayRole)
        if text:
            fg_brush = index.data(QtCore.Qt.ItemDataRole.ForegroundRole)
            if fg_brush and isinstance(fg_brush, QtGui.QBrush):
                painter.setPen(fg_brush.color())
            elif fg_brush and isinstance(fg_brush, QtGui.QColor):
                painter.setPen(fg_brush)
            elif option.state & QtWidgets.QStyle.StateFlag.State_Selected:
                painter.setPen(option.palette.highlightedText().color())
            else:
                painter.setPen(option.palette.text().color())
            font_data = index.data(QtCore.Qt.ItemDataRole.FontRole)
            if font_data and isinstance(font_data, QtGui.QFont):
                painter.setFont(font_data)
            else:
                painter.setFont(option.font)
            text_rect = rect.adjusted(4, 0, -4, 0)
            painter.drawText(QtCore.QRectF(text_rect),
                             QtCore.Qt.AlignmentFlag.AlignVCenter | QtCore.Qt.AlignmentFlag.AlignLeft,
                             str(text))

        # 테두리 (UserRole+100에 색상이 설정된 경우)
        border_color = index.data(self.BORDER_ROLE)
        if border_color and isinstance(border_color, QtGui.QColor):
            pen = QtGui.QPen(border_color, 0.5)
            painter.setPen(pen)
            painter.setBrush(QtCore.Qt.BrushStyle.NoBrush)
            painter.drawRoundedRect(QtCore.QRectF(rect), self._RADIUS, self._RADIUS)

        painter.restore()


class PathElideDelegate(QtWidgets.QStyledItemDelegate):
    """경로 텍스트를 ElideMiddle로 표시하는 delegate.
    전체 경로가 셀에 다 들어가지 않으면 중간을 ...으로 줄여 표시."""

    def paint(self, painter, option, index):
        # 기본 배경/선택 상태 그리기
        self.initStyleOption(option, index)
        painter.save()
        # 배경
        style = option.widget.style() if option.widget else QtWidgets.QApplication.style()
        style.drawPrimitive(QtWidgets.QStyle.PrimitiveElement.PE_PanelItemViewItem, option, painter, option.widget)
        # 텍스트 ElideMiddle 처리
        text = index.data(QtCore.Qt.ItemDataRole.DisplayRole) or ""
        rect = style.subElementRect(QtWidgets.QStyle.SubElement.SE_ItemViewItemText, option, option.widget)
        rect.adjust(2, 0, -2, 0)
        fm = painter.fontMetrics()
        elided = fm.elidedText(text, QtCore.Qt.TextElideMode.ElideMiddle, rect.width())
        painter.setPen(option.palette.color(
            QtGui.QPalette.ColorGroup.Normal if option.state & QtWidgets.QStyle.StateFlag.State_Enabled
            else QtGui.QPalette.ColorGroup.Disabled,
            QtGui.QPalette.ColorRole.Text))
        painter.drawText(rect, QtCore.Qt.AlignmentFlag.AlignVCenter | QtCore.Qt.AlignmentFlag.AlignLeft, elided)
        painter.restore()


class Ui_sitool(object):
    # ── 세그먼티드 컨트롤 헬퍼 ──
    @staticmethod
    def _make_seg_group(labels, parent, button_group, font,
                        checked_idx=0):
        """묶음 토글 버튼 그룹 생성 (PyQt6 기본 스타일).

        Returns
        -------
        container : QWidget
            버튼들을 감싸는 컨테이너 위젯
        buttons : list[QPushButton]
            생성된 버튼 목록 (인덱스 = button_group id)
        """
        container = QtWidgets.QWidget(parent)
        h = QtWidgets.QHBoxLayout(container)
        h.setContentsMargins(0, 0, 0, 0)
        h.setSpacing(2)

        _fb = QtGui.QFont(font)
        _fb.setBold(True)
        _fm = QtGui.QFontMetrics(_fb)

        buttons = []
        for i, text in enumerate(labels):
            btn = QtWidgets.QPushButton(text, parent=container)
            btn.setCheckable(True)
            btn.setFont(font)
            # bold(체크 시) 렌더링 편차 + PyQt6 기본 버튼 좌우 padding 흡수
            btn.setMinimumWidth(_fm.horizontalAdvance(text) + 28)
            if i == checked_idx:
                btn.setChecked(True)
            button_group.addButton(btn, i)
            h.addWidget(btn)
            buttons.append(btn)
        return container, buttons

