                                            if temp[1].iloc[0,2] == 100:
                                                self.cycle_tab.addTab(tab, "dchg" + str(dchg_tab_no))
                                                dchg_tab_no = dchg_tab_no + 1
                                            else:
                                                self.cycle_tab.addTab(tab, "chg" + str(chg_tab_no))
