    def table_reset(self):
        self.tb_channel.clear()
        # 필터링 모드에서 변경된 헤더/컬럼 수를 기본값으로 복원
        self.tb_channel.setColumnCount(8)
        self.tb_channel.setRowCount(16)
        self.tb_channel.horizontalHeader().setVisible(False)
        self.tb_channel.horizontalHeader().setSectionResizeMode(QtWidgets.QHeaderView.ResizeMode.Stretch)
        self.tb_modified_time.setText("")

    def match_highlight_text(self, search_text, testname):
        """멀티 단어 검색: 스페이스=OR, 쉼표=AND, 대소문자 무시"""
        if search_text.strip() == "":
            return True
        import re
        # 쉼표 주변 스페이스 제거 → "A, B" → "A,B" (AND 보존)
        normalized = re.sub(r'\s*,\s*', ',', search_text)
        testname_lower = testname.lower()
        for group in normalized.split(" "):
            group = group.strip()
            if not group:
                continue
            keywords = [kw.strip().lower() for kw in group.split(",") if kw.strip()]
            if keywords and all(kw in testname_lower for kw in keywords):
                return True
        return False

    # ───────────────────────────────────────────────────────────────
    # 상태 분류 상수 (v3 재설계 — 260415 redesign 문서 참조)
    # ───────────────────────────────────────────────────────────────
    # 안전조건 Code (→ 빨강 배경)
    #   128/129: 전압 상하한, 134: OCV상한, 142: 용량상한,
    #   208/209: 전압/전류 이상(경고)
    SAFETY_CODES = frozenset({"128", "129", "134", "142", "208", "209"})

    # .log 세분화 결과 → 노랑 (사용자 조작 또는 원인 불명)
    USER_OR_ERROR_LABELS = frozenset({
        "사용자멈춤",
        "작업멈춤",   # _classify_paused_reason 의 fallback 반환값
        "잠시멈춤",   # 작업멈춤과 동일 계열 (PNE State 변형)
        # "중단점 도달 (S*/C*)" 는 startswith 로 판정
    })

    # .log 세분화 결과 → 빨강 (하드웨어/챔버 이슈)
    HW_WARNING_LABELS = frozenset({
        "챔버이슈",
    })

    # 완료 계열 (셀있음) → 연녹
    COMPLETED_LABELS = frozenset({
        "완료",       # JSON State == "완료"
        "시험완료",   # .log: Test work completed
    })

    # 안전조건 Code_Desc 텍스트 (JSON 원본값)
    SAFETY_CODE_DESCS = frozenset({
        "전압 상한", "전압 하한", "OCV상한", "용량상한",
        "전압 이상(경고)", "전류 이상(경고)",
    })

    # 상태 키워드 매핑 (키워드 추가 시 여기만 수정)
    # None    = _NORMAL_STATES에 속하지 않는 모든 상태 (작업멈춤 계열)
    # frozenset = 상태값이 해당 집합에 포함되는지 검사 (prefix 매칭 포함)
    FILTER_STATUS_KEYWORDS = {
        "유휴": ["완료", "준비", "작업정지"],
        "작업멈춤": None,
        "안전조건": SAFETY_CODE_DESCS,
        "사용자멈춤계": frozenset({
            "사용자멈춤", "챔버이슈", "시험완료", "작업멈춤", "잠시멈춤",
            # "중단점 도달" 은 startswith 로 처리
        }),
    }

    def match_filter_text(self, search_text, testname, status):
        """필터링용 매칭: 상태 키워드 또는 테스트명 텍스트 검색
        스페이스=OR, 쉼표=AND, 대소문자 무시
        키워드(유휴, 작업멈춤 등)는 상태 컬럼에서 매칭
        작업멈춤: _NORMAL_STATES에 속하지 않는 모든 상태 매칭
        사용자멈춤계: "중단점 도달 (...)" 접두사도 포함"""
        if search_text.strip() == "":
            return True
        # 상태 base (괄호 접미사 제거)
        status_base = status.split(" (")[0] if " (" in status else status
        normalized = re.sub(r'\s*,\s*', ',', search_text)
        testname_lower = testname.lower()
        for group in normalized.split(" "):
            group = group.strip()
            if not group:
                continue
            keywords = [kw.strip() for kw in group.split(",") if kw.strip()]
            if not keywords:
                continue
            # AND 조건: 그룹 내 모든 키워드가 매칭되어야 함
            all_match = True
            for kw in keywords:
                if kw in self.FILTER_STATUS_KEYWORDS:
                    allowed = self.FILTER_STATUS_KEYWORDS[kw]
                    if allowed is None:
                        # 작업멈춤 계열: 정상 상태가 아닌 모든 것
                        if status in self._NORMAL_STATES:
                            all_match = False
                            break
                    elif isinstance(allowed, frozenset):
                        # 집합 포함 여부 + "중단점 도달" prefix 특수 처리
                        hit = status_base in allowed
                        if not hit and kw == "사용자멈춤계":
                            hit = status.startswith("중단점 도달")
                        if not hit:
                            all_match = False
                            break
                    else:
                        # list 타입 (기존 "유휴")
                        if status not in allowed:
                            all_match = False
                            break
                else:
                    # 일반 텍스트 → testname 또는 status_base 에서 매칭
                    kw_low = kw.lower()
                    if (kw_low not in testname_lower
                            and kw not in status_base):
                        all_match = False
                        break
            if all_match:
                return True
        return False

    # 정상 운전 상태 (이 외 = 작업멈춤 계열)
    _NORMAL_STATES = frozenset({
        "작업중", "충전", "방전", "진행", "휴지",
        "완료", "대기", "준비", "작업정지",
    })

    @staticmethod
    def _pne_sync_time(js: dict) -> str:
        """PNE JSON 첫 번째 채널의 Sync_Time_Day + Sync_Time → "YY-MM-DD HH:MM"

        Sync_Time_Day: "20260414" (yyyymmdd)
        Sync_Time:     "162017055" (HHMMSSnn)
        """
        try:
            ch0 = js["Channel"][0]
            day = str(ch0.get("Sync_Time_Day", ""))
            time = str(ch0.get("Sync_Time", ""))
            if len(day) >= 8 and len(time) >= 4:
                return f"{day[2:4]}-{day[4:6]}-{day[6:8]} {time[:2]}:{time[2:4]}"
        except (IndexError, KeyError, TypeError):
            pass
        return ""

    @staticmethod
    def _read_log_tail(channel_path: str) -> str | None:
        """채널 폴더의 최신 .log 파일 끝부분 읽기 (점진적 확장)

        4KB부터 시작하여 act/Paused/Test work completed 키워드가 없으면
        16KB → 64KB로 점진적으로 확장. Recovery 로그 등으로 끝부분이
        채워진 예외 케이스 대응. 키워드 발견 즉시 반환하여 불필요한
        네트워크 I/O 방지.
        """
        try:
            if not os.path.isdir(channel_path):
                return None
            log_files = [f.path for f in os.scandir(channel_path)
                         if f.name.endswith('.log') and f.is_file()]
            if not log_files:
                return None
            log_path = max(log_files, key=os.path.getmtime)
            file_size = os.path.getsize(log_path)
            for read_size in (4096, 16384, 65536):
                if file_size <= read_size:
                    # 파일 전체 읽기 (더 확장해도 의미 없음)
                    with open(log_path, 'r', encoding='cp949', errors='ignore') as f:
                        return f.read()
                with open(log_path, 'r', encoding='cp949', errors='ignore') as f:
                    f.seek(file_size - read_size)
                    f.readline()  # 잘린 첫 줄 버림
                    content = f.read()
                # 핵심 키워드 발견 시 즉시 반환
                if ("act" in content or "Paused" in content
                        or "Test work completed" in content):
                    return content
            # 64KB까지 읽었는데도 키워드 없음 → 그대로 반환 (fallback)
            return content
        except Exception:
            return None

    @staticmethod
    def _extract_log_time(line: str) -> str:
        """로그 줄에서 타임스탬프 추출 ("2026/04/13 09:39:09 :: ..." → datetime str)"""
        m = re.match(r'(\d{4}/\d{2}/\d{2}\s+\d{2}:\d{2}:\d{2})', line)
        return m.group(1) if m else ""

    @staticmethod
    def _elapsed_str(log_time: str) -> str:
        """로그 시각 → 현재까지 경과 문자열 ("3d 5h", "2h", "45m")"""
        if not log_time:
            return ""
        try:
            dt = datetime.strptime(log_time, "%Y/%m/%d %H:%M:%S")
            delta = datetime.now() - dt
            total_min = int(delta.total_seconds() / 60)
            if total_min < 0:
                return ""
            if total_min < 60:
                return f"{total_min}m"
            hours = total_min // 60
            if hours < 24:
                return f"{hours}h"
            days = hours // 24
            rem_h = hours % 24
            if rem_h > 0:
                return f"{days}d {rem_h}h"
            return f"{days}d"
        except (ValueError, TypeError):
            return ""

    @staticmethod
    def _classify_paused_reason(channel_path: str) -> tuple[str, str]:
        """Code:153 작업멈춤 채널의 .log에서 중단 사유 판별

        입력 계층 (JSON-우선 원칙):
        - 호출부가 JSON(State=작업멈춤 + Code=153)으로 '멈춤' 대분류 확정
        - 본 함수는 .log를 *참조*하여 세분 사유 결정
        - .log 불완전/누락 시 .csv(Restore/) 및 .cyc mtime으로 교차 검증

        마지막 act 줄과 마지막 Paused 줄 중 더 뒤에 있는 것이 현재 상태:
        - act가 뒤: act 내용으로 직접 판별
        - Paused가 뒤: Paused 윗줄 act로 판별

        Returns
        -------
        tuple[str, str]
            (사유, 경과시간) — 예: ("중단점 도달 (S201/C89)", "3d 5h")
        """
        tail = WindowClass._read_log_tail(channel_path)
        if tail is None:
            # .log 접근 실패/부재 → CSV/CYC mtime 교차검증
            return "작업멈춤", WindowClass._crosscheck_elapsed(channel_path)
        lines = tail.splitlines()
        # ── 마지막 "act" / "Paused" / "Test work completed" 위치 (역순) ──
        last_act_idx, last_paused_idx, last_completed_idx = -1, -1, -1
        for i in range(len(lines) - 1, -1, -1):
            if last_act_idx < 0 and "act" in lines[i]:
                last_act_idx = i
            if last_paused_idx < 0 and "Paused" in lines[i]:
                last_paused_idx = i
            if last_completed_idx < 0 and "Test work completed" in lines[i]:
                last_completed_idx = i
            if last_act_idx >= 0 and last_paused_idx >= 0 and last_completed_idx >= 0:
                break
        # ── "Test work completed"가 가장 뒤: 시험 정상 종료 ──
        if last_completed_idx > last_act_idx and last_completed_idx > last_paused_idx:
            log_time = WindowClass._extract_log_time(lines[last_completed_idx])
            return "시험완료", WindowClass._elapsed_str(log_time)
        # ── act가 Paused보다 뒤 (또는 Paused 없음): act 줄로 직접 판별 ──
        # 호출부는 이미 State=작업멈춤/잠시멈춤 + Code=153 을 확정한 뒤 이 함수를
        # 부르므로, Paused 줄 누락(PNE 미기록) 이어도 '작업중' 반환은 모순.
        # → 멈춤 사유만 세분 분류한다.
        if last_act_idx > last_paused_idx:
            act_line = lines[last_act_idx]
            log_time = WindowClass._extract_log_time(act_line)
            elapsed = WindowClass._elapsed_str(log_time)
            # Reserve Cycle 패턴 → 예약 지점에 도달해 멈춘 것으로 해석
            # (PNE가 Paused 이벤트를 .log에 기록하지 못한 케이스 포함)
            reserve_m = re.search(
                r'Reserve Cycle:\s*(\d+),\s*Step:\s*(\d+)', act_line)
            if reserve_m:
                rc, rs = reserve_m.group(1), reserve_m.group(2)
                return f"중단점 도달 (S{rs}/C{rc})", elapsed
            # 사용자 멈춤 (즉시 멈춤/완료)
            if "즉시 멈춤 시행" in act_line or "즉시 완료 시행" in act_line:
                return "사용자멈춤", elapsed
            # 그 외 act (작업 시작/계속/다음 Step) → 일반 작업멈춤
            # .log act 시각이 비거나 매우 오래됐으면 CSV/CYC 교차검증으로 보강
            if not elapsed:
                elapsed = WindowClass._crosscheck_elapsed(channel_path)
            return "작업멈춤", elapsed
        # ── Paused가 뒤: Paused 내용 + 윗줄 act로 판별 ──
        if last_paused_idx >= 0:
            paused_line = lines[last_paused_idx]
            # 챔버 이슈
            if "chamber alarm" in paused_line:
                log_time = WindowClass._extract_log_time(paused_line)
                return "챔버이슈", WindowClass._elapsed_str(log_time)
            # Paused 윗줄에서 가장 가까운 act 줄
            act_line = ""
            for i in range(last_paused_idx - 1, -1, -1):
                if "act" in lines[i]:
                    act_line = lines[i]
                    break
            log_time = WindowClass._extract_log_time(act_line) or \
                       WindowClass._extract_log_time(paused_line)
            elapsed = WindowClass._elapsed_str(log_time)
            reserve_m = re.search(
                r'Reserve Cycle:\s*(\d+),\s*Step:\s*(\d+)', act_line)
            if reserve_m:
                rc, rs = reserve_m.group(1), reserve_m.group(2)
                return f"중단점 도달 (S{rs}/C{rc})", elapsed
            if "즉시 멈춤 시행" in act_line or "즉시 완료 시행" in act_line:
                return "사용자멈춤", elapsed
            if not elapsed:
                elapsed = WindowClass._crosscheck_elapsed(channel_path)
            return "작업멈춤", elapsed
        # ── tail 내 키워드 전무 → CSV/CYC 교차검증으로 elapsed 보강 ──
        return "작업멈춤", WindowClass._crosscheck_elapsed(channel_path)

    @staticmethod
    def _parse_reserve_info(channel_path: str) -> str:
        """작업중 채널의 .log에서 Reserve 예약 정보 추출

        마지막 "act" 줄 기준:
        - "작업 계속 act" / "다음 Step act" → 진행중 (예약 없음)
        - "act 즉시 멈춤 시행 (...Reserve...)" → 예약 있음

        Returns
        -------
        str
            "→S{rs}/C{rc}" (예약 있음) | "" (진행중/예약 없음)
        """
        tail = WindowClass._read_log_tail(channel_path)
        if tail is None:
            return ""
        # 마지막 "act" 줄 찾기 (역순)
        last_act = ""
        for line in reversed(tail.splitlines()):
            if "act" in line:
                last_act = line
                break
        if not last_act:
            return ""
        # "작업 계속 act" / "다음 Step act" → 진행중 (예약 없음)
        if "작업 계속 act" in last_act or "다음 Step act" in last_act:
            return ""
        # Reserve 패턴 추출
        reserve_m = re.search(
            r'Reserve Cycle:\s*(\d+),\s*Step:\s*(\d+)', last_act)
        if reserve_m:
            rc, rs = reserve_m.group(1), reserve_m.group(2)
            return f"→S{rs}/C{rc}"
        return ""

    @staticmethod
    def _elapsed_from_log(channel_path: str) -> str:
        """채널 폴더의 .log/.cyc mtime 중 더 최근 값 → 경과 문자열.

        .log를 기록하지 않는 버그 케이스 대비 .cyc mtime도 함께 비교.
        두 파일 중 더 최근(=마지막 활동 시각)을 경과 기준으로 사용.

        1차: .log mtime vs .cyc mtime 비교 → 최신 값 사용
        2차: mtime 이 미래 (시스템 시간 불일치) → .log tail 타임스탬프

        return
        ------
        str : "3d 5h" / "2h" / "45m" 형식, 실패 시 ""
        """
        try:
            if not os.path.isdir(channel_path):
                return ""
            # .log / .cyc mtime 수집
            best_dt = None
            for f in os.scandir(channel_path):
                if f.is_file() and (f.name.endswith('.log') or f.name.endswith('.cyc')):
                    mt = datetime.fromtimestamp(os.path.getmtime(f.path))
                    if best_dt is None or mt > best_dt:
                        best_dt = mt
            if best_dt is not None and (datetime.now() - best_dt).total_seconds() >= 0:
                return WindowClass._elapsed_str(best_dt.strftime("%Y/%m/%d %H:%M:%S"))
            # fallback: .log tail 마지막 타임스탬프
            log_files = [f.path for f in os.scandir(channel_path)
                         if f.name.endswith('.log') and f.is_file()]
            if log_files:
                log_path = max(log_files, key=os.path.getmtime)
                tail = WindowClass._read_log_tail(log_path) or ""
                for ln in reversed(tail.splitlines()):
                    log_time = WindowClass._extract_log_time(ln)
                    if log_time:
                        return WindowClass._elapsed_str(log_time)
            return ""
        except Exception:
            return ""

    @staticmethod
    def _get_cyc_mtime(channel_path: str):
        """채널 폴더의 최신 .cyc 파일 mtime → datetime | None."""
        try:
            if not os.path.isdir(channel_path):
                return None
            cyc_files = [f.path for f in os.scandir(channel_path)
                         if f.name.endswith('.cyc') and f.is_file()]
            if not cyc_files:
                return None
            newest = max(cyc_files, key=os.path.getmtime)
            return datetime.fromtimestamp(os.path.getmtime(newest))
        except Exception:
            return None

    @staticmethod
    def _get_csv_mtime(channel_path: str):
        """채널 폴더 내 Restore\\*.csv 중 최신 mtime → datetime | None.

        SaveEndData.csv 는 스텝 완료 시 PNE가 기록하는 요약 CSV.
        .log에 Paused 이벤트가 누락되는 PNE 펌웨어 버그 케이스에서
        실제 데이터 기록 중단 시점을 교차 검증할 수 있는 3차 소스.

        계층: JSON(1순위) → .log(참조) → .csv/.cyc(교차검증)
        """
        try:
            if not os.path.isdir(channel_path):
                return None
            restore_path = os.path.join(channel_path, "Restore")
            if not os.path.isdir(restore_path):
                return None
            csv_files = [f.path for f in os.scandir(restore_path)
                         if f.name.lower().endswith('.csv') and f.is_file()]
            if not csv_files:
                return None
            newest = max(csv_files, key=os.path.getmtime)
            return datetime.fromtimestamp(os.path.getmtime(newest))
        except Exception:
            return None

    @staticmethod
    def _crosscheck_elapsed(channel_path: str) -> str:
        """.csv (Restore/) / .cyc mtime 중 최신 → 경과 문자열.

        .log 가 불완전하거나 Paused 이벤트 미기록 시 elapsed_str 보강용.
        PNE는 스텝 완료 시 CSV를, 실시간 데이터를 .cyc에 기록하므로
        두 파일의 최신 mtime이 채널의 마지막 활동 시각에 근접.
        """
        csv_dt = WindowClass._get_csv_mtime(channel_path)
        cyc_dt = WindowClass._get_cyc_mtime(channel_path)
        candidates = [dt for dt in (csv_dt, cyc_dt) if dt is not None]
        if not candidates:
            return ""
        best_dt = max(candidates)
        return WindowClass._elapsed_str(
            best_dt.strftime("%Y/%m/%d %H:%M:%S"))

    def _refine_paused_status(self, df: pd.DataFrame) -> pd.DataFrame:
        """채널 상태 세부 분류 — JSON 1순위 + .log 참조 + CSV 교차검증.

        JSON 우선 원칙:
        - Code=153 + Code_Desc ∈ {작업멈춤종료, 잠시멈춤} 이면 State 값과
          무관하게 '멈춤' 확정 → .log 로 세분 사유 판별.
        - State=작업멈춤/잠시멈춤 이지만 Code≠153 이면 Code_Desc 텍스트 사용.

        분류 결과:
        1) Code=153 (state 무관): .log 파싱 → "중단점 도달 (S{rs}/C{rc})" /
           "사용자멈춤" / "챔버이슈" / "작업멈춤" / "시험완료"
        2) State=멈춤 + Code≠153: "작업멈춤 - {Code_Desc}"

        Note: df["path"]는 change_drive()에서 채널폴더가 잘린 상위 경로.
        .log 파일은 채널폴더 내부에 있으므로 Result_Path에서 채널폴더명을
        추출하여 붙인다.
        """
        has_code = "Code" in df.columns
        has_code_desc = "Code_Desc" in df.columns
        has_rpath = "Result_Path" in df.columns
        has_path = "path" in df.columns
        # JSON 1순위: State OR (Code=153 + Code_Desc) 로 확장 마스킹
        state_mask = df["use"].isin(("작업멈춤", "잠시멈춤"))
        if has_code and has_code_desc:
            code_series = df["Code"].astype(str).str.strip()
            cd_series = df["Code_Desc"].astype(str).str.strip()
            code_mask = (code_series == "153") & cd_series.isin(
                ("작업멈춤종료", "잠시멈춤"))
            mask = state_mask | code_mask
        else:
            mask = state_mask
        if not mask.any():
            return df
        for idx in df.index[mask]:
            code = str(df.at[idx, "Code"]).strip() if has_code else ""
            code_desc = str(df.at[idx, "Code_Desc"]).strip() if has_code_desc else ""
            if code == "153" and code_desc in ("작업멈춤종료", "잠시멈춤"):
                ch_path = self._build_channel_path(df, idx, has_rpath, has_path)
                if ch_path:
                    reason, _ = self._classify_paused_reason(ch_path)
                    df.at[idx, "use"] = reason
            elif code_desc:
                df.at[idx, "use"] = f"작업멈춤 - {code_desc}"
        return df

    @staticmethod
    def _build_channel_path(df: pd.DataFrame, idx: int,
                            has_rpath: bool, has_path: bool) -> str:
        """Result_Path에서 채널폴더명을 추출하여 드라이브 치환된 경로 구성"""
        if has_rpath and has_path:
            rpath = str(df.at[idx, "Result_Path"]).rstrip("\\")
            base = str(df.at[idx, "path"])
            channel_folder = rpath[rpath.rfind("\\") + 1:]
            return os.path.join(base, channel_folder)
        if has_path:
            return str(df.at[idx, "path"])
        return ""

    def change_drive(self, df, changed):
        # 상세 데이터부터 범용 데이터 순으로 바꾸기 진행
        original_drive = ["D:\\Data\\", "D:\\DATA\\","D:\\", "E:\\Data\\", "E:\\DATA\\", "E:\\"]
        df["path"] = df["Result_Path"].apply(lambda x: x[:x.rfind('\\')+1])
        for cycler_drive in original_drive:
            df["path"] = df["path"].str.replace(cycler_drive, changed)
        return df

    def cycle_error(self):
        err_msg('파일 or 경로없음!!','C드라이브에 cycler_path.txt 파일이 없거나 toyo/PNE 경로 설정 오류')

    def _filter_context_menu(self, pos) -> None:
        """필터링 테이블 우클릭 메뉴"""
        if not self._filter_sections:
            return
        menu = QtWidgets.QMenu(self.tb_channel)
        menu.addAction("전체 펼침", self._filter_expand_all)
        menu.addAction("전체 닫힘", self._filter_collapse_all)
        menu.exec(self.tb_channel.viewport().mapToGlobal(pos))

    def _filter_expand_all(self) -> None:
        """필터링 테이블 모든 섹션 펼침"""
        for row, sec in self._filter_sections.items():
            sec['collapsed'] = False
            for r in sec['rows']:
                self.tb_channel.setRowHidden(r, False)
            item = self.tb_channel.item(row, 0)
            if item:
                item.setText(item.text().replace("▸", "▾", 1))

    def _filter_collapse_all(self) -> None:
        """필터링 테이블 모든 섹션 닫힘"""
        # 충방전기 섹션 먼저 접고, 층 섹션 접기
        for row, sec in self._filter_sections.items():
            if sec['type'] == 'cycler':
                sec['collapsed'] = True
                for r in sec['rows']:
                    self.tb_channel.setRowHidden(r, True)
                item = self.tb_channel.item(row, 0)
                if item:
                    item.setText(item.text().replace("▾", "▸", 1))
        for row, sec in self._filter_sections.items():
            if sec['type'] == 'floor':
                sec['collapsed'] = True
                for r in sec['rows']:
                    self.tb_channel.setRowHidden(r, True)
                item = self.tb_channel.item(row, 0)
                if item:
                    item.setText(item.text().replace("▾", "▸", 1))

    def _filter_toggle_section(self, row: int, _col: int) -> None:
        """필터링 테이블 헤더 행 클릭 → 하위 행 접기/펼치기"""
        sec = self._filter_sections.get(row)
        if sec is None:
            return
        collapsed = not sec['collapsed']
        sec['collapsed'] = collapsed
        # 하위 행 숨기기/보이기
        for r in sec['rows']:
            self.tb_channel.setRowHidden(r, collapsed)
            # 층 접기 시 하위 충방전기 섹션도 동기화
            if sec['type'] == 'floor' and r in self._filter_sections:
                child = self._filter_sections[r]
                if collapsed:
                    for cr in child['rows']:
                        self.tb_channel.setRowHidden(cr, True)
                elif not child['collapsed']:
                    for cr in child['rows']:
                        self.tb_channel.setRowHidden(cr, False)
        # 헤더 아이콘 변경 (▾↔▸)
        item = self.tb_channel.item(row, 0)
        if item:
            text = item.text()
            if collapsed:
                item.setText(text.replace("▾", "▸", 1))
            else:
                item.setText(text.replace("▸", "▾", 1))

    def eventFilter(self, obj: QtCore.QObject, event: QtCore.QEvent) -> bool:
        """FindText Enter → 강조, Shift+Enter → 필터링"""
        if obj is self.FindText and event.type() == QtCore.QEvent.Type.KeyPress:
            key = event.key()
            if key in (QtCore.Qt.Key.Key_Return, QtCore.Qt.Key.Key_Enter):
                if event.modifiers() & QtCore.Qt.KeyboardModifier.ShiftModifier:
                    self.filter_all_channels()
                else:
                    self.tb_cycler_combobox()
                return True
        return super().eventFilter(obj, event)

