    def _tb_channel_copy(self) -> None:
        """tb_channel 선택 영역을 탭 구분 텍스트로 클립보드에 복사"""
        sel = self.tb_channel.selectedIndexes()
        if not sel:
            return
        # 행/열 범위 계산
        rows = sorted(set(idx.row() for idx in sel))
        cols = sorted(set(idx.column() for idx in sel))
        lines = []
        for r in rows:
            cells = []
            for c in cols:
                item = self.tb_channel.item(r, c)
                cells.append(item.text() if item else "")
            lines.append('\t'.join(cells))
        QtWidgets.QApplication.clipboard().setText('\n'.join(lines))

    def filter_all_channels(self) -> None:
        """전체 충방전기에서 검색 조건에 맞는 채널을 층별/충방전기별 그룹으로 출력
        빈 텍스트: 유휴 채널 필터링 (완료/준비/작업정지)"""
        search_text = str(self.FindText.text()).strip()
        # 빈 텍스트 → 유휴 채널 검색 모드
        is_idle_mode = not search_text
        if is_idle_mode:
            search_text = "유휴"
        # 층별 충방전기 매핑 (tb_room 콤보박스와 동일 구조)
        floor_cyclers = [
            ("R5 15F", ["Toyo1", "Toyo2", "Toyo3", "Toyo4", "Toyo5",
                        "PNE1", "PNE2", "PNE3", "PNE4", "PNE5"]),
            ("R5 3F B-1", ["PNE01", "PNE02", "PNE03", "PNE04", "PNE05",
                           "PNE06", "PNE07", "PNE08"]),
            ("R5 3F B-2", ["PNE09", "PNE10", "PNE11", "PNE12", "PNE13",
                           "PNE14", "PNE15", "PNE16"]),
            ("R5 3F A", ["PNE17", "PNE18", "PNE19", "PNE20", "PNE21",
                         "PNE22", "PNE23", "PNE24", "PNE25"]),
        ]
        toyo_info = {
            "Toyo1": (0, self.toyo_cycler_name[0]),
            "Toyo2": (1, self.toyo_cycler_name[1]),
            "Toyo3": (2, self.toyo_cycler_name[2]),
            "Toyo4": (3, self.toyo_cycler_name[3]),
            "Toyo5": (4, self.toyo_cycler_name[4]),
        }
        pne_info = {
            "PNE1": (0, self.pne_cycler_name[0]),
            "PNE2": (1, self.pne_cycler_name[1]),
            "PNE3": (2, self.pne_cycler_name[2]),
            "PNE4": (3, self.pne_cycler_name[3]),
            "PNE5": (4, self.pne_cycler_name[4]),
            "PNE01": (5, self.pne_cycler_name[5]),
            "PNE02": (6, self.pne_cycler_name[6]),
            "PNE03": (7, self.pne_cycler_name[7]),
            "PNE04": (8, self.pne_cycler_name[8]),
            "PNE05": (9, self.pne_cycler_name[9]),
            "PNE06": (10, self.pne_cycler_name[10]),
            "PNE07": (11, self.pne_cycler_name[11]),
            "PNE08": (12, self.pne_cycler_name[12]),
            "PNE09": (13, self.pne_cycler_name[13]),
            "PNE10": (14, self.pne_cycler_name[14]),
            "PNE11": (15, self.pne_cycler_name[15]),
            "PNE12": (16, self.pne_cycler_name[16]),
            "PNE13": (17, self.pne_cycler_name[17]),
            "PNE14": (18, self.pne_cycler_name[18]),
            "PNE15": (19, self.pne_cycler_name[19]),
            "PNE16": (20, self.pne_cycler_name[20]),
            "PNE17": (21, self.pne_cycler_name[21]),
            "PNE18": (22, self.pne_cycler_name[22]),
            "PNE19": (23, self.pne_cycler_name[23]),
            "PNE20": (24, self.pne_cycler_name[24]),
            "PNE21": (25, self.pne_cycler_name[25]),
            "PNE22": (26, self.pne_cycler_name[26]),
            "PNE23": (27, self.pne_cycler_name[27]),
            "PNE24": (28, self.pne_cycler_name[28]),
            "PNE25": (29, self.pne_cycler_name[29]),
        }
        # 전체 충방전기 리스트 구성 (모든 층 합산)
        all_cyclers = []
        for _, cyclers in floor_cyclers:
            all_cyclers.extend(cyclers)
        # 전체 충방전기를 순회하며 데이터 로드 + 매칭 채널 수집
        # matched_by_floor: {층: {충방전기: [(채널번호, 테스트명, 상태, cyc, vol, cell_path)]}}
        matched_by_floor = {}
        # cycler_mtime: {충방전기: "YYYY-MM-DD HH:MM"} 최종 업데이트 시간
        cycler_mtime = {}
        total_matched = 0
        total_channels = 0
        working_count = 0
        idle_no_cell = 0   # 대기-셀없음 (유휴 + vol=="-")
        idle_has_cell = 0  # 대기-셀있음 (유휴 + vol!="-")
        self.progressBar.setValue(0)
        QtWidgets.QApplication.processEvents()
        total = len(all_cyclers)
        for idx, cycler_text in enumerate(all_cyclers):
            try:
                mtime_str = ""
                if cycler_text in toyo_info:
                    num, name = toyo_info[cycler_text]
                    # 최종 업데이트 시간
                    cfg_path = "z:\\Working\\" + self.toyo_blk_list[num] + "\\Chpatrn.cfg"
                    if os.path.isfile(cfg_path):
                        mtime_str = datetime.fromtimestamp(
                            os.path.getmtime(cfg_path)).strftime("%m-%d %H:%M")
                    df = self.toyo_data_make(num, name)
                elif cycler_text in pne_info:
                    num, name = pne_info[cycler_text]
                    df = self.pne_data_make(num, name)
                    # 최종 동기화 시간 (JSON Sync_Time 기반)
                    mtime_str = getattr(self, '_pne_last_sync_time', '')
                else:
                    continue
                cycler_mtime[cycler_text] = mtime_str
                if df is None or df.empty:
                    continue
                total_channels += len(df)
                for ch_idx in df.index:
                    testname = str(df.loc[ch_idx, "testname"])
                    status = str(df.loc[ch_idx, "use"])
                    cyc = str(df.loc[ch_idx, "cyc"]) if "cyc" in df.columns else "-"
                    vol = str(df.loc[ch_idx, "vol"]) if "vol" in df.columns else "-"
                    # 셀 경로: Toyo=folder, PNE=path
                    if "path" in df.columns:
                        cell_path = str(df.loc[ch_idx, "path"])
                    elif "folder" in df.columns:
                        cell_path = str(df.loc[ch_idx, "folder"])
                    else:
                        cell_path = ""
                    # 동작 타입 추출 (작업중일 때만 Type 표시)
                    type_str = ""
                    if status in ("작업중", "충전", "방전", "진행", "휴지"):
                        if "Type" in df.columns:
                            type_str = str(df.loc[ch_idx, "Type"]).strip()
                            if type_str in ("", "nan"):
                                type_str = ""
                            elif type_str == "휴지":
                                type_str = "Rest"
                    # 온도 추출
                    temp_str = "-"
                    if "temp" in df.columns:
                        try:
                            raw_temp = df.loc[ch_idx, "temp"]
                            t_val = float(raw_temp)
                            # PNE: mC 단위 (×1000), Toyo: °C 문자열
                            if abs(t_val) > 200:
                                temp_str = f"{t_val / 1000:.1f}"
                            else:
                                temp_str = f"{t_val:.1f}"
                        except (ValueError, TypeError):
                            temp_str = str(raw_temp) if raw_temp else "-"
                    if self.match_filter_text(search_text, testname, status):
                        elapsed_str = ""
                        # PNE 채널만 .log 기반 세분류 (v4: JSON 1순위 + .log 참조 + CSV 교차검증)
                        if cycler_text in pne_info:
                            has_rpath = "Result_Path" in df.columns
                            has_path = "path" in df.columns
                            # JSON 우선 추출 — status 분기 전에 Code/Code_Desc 확정
                            code = str(df.loc[ch_idx, "Code"]).strip() if "Code" in df.columns else ""
                            code_desc = str(df.loc[ch_idx, "Code_Desc"]).strip() if "Code_Desc" in df.columns else ""
                            is_paused_by_code = (
                                code == "153"
                                and code_desc in ("작업멈춤종료", "잠시멈춤")
                            )
                            # (A) Code=153 + 작업멈춤종료/잠시멈춤 → State 무관 멈춤 확정
                            #     JSON 1순위: State가 '작업중'이어도 Code가 멈춤이면 멈춤
                            if is_paused_by_code:
                                ch_path = self._build_channel_path(
                                    df, ch_idx, has_rpath, has_path)
                                if ch_path:
                                    status, elapsed_str = self._classify_paused_reason(ch_path)
                                else:
                                    # 경로 구성 실패 fallback
                                    status = "작업멈춤"
                            # (B) 작업멈춤/잠시멈춤 + Code != 153 → Code_Desc 그대로
                            elif status in ("작업멈춤", "잠시멈춤"):
                                if code_desc:
                                    status = code_desc
                                ch_path = self._build_channel_path(
                                    df, ch_idx, has_rpath, has_path)
                                if ch_path:
                                    elapsed_str = self._elapsed_from_log(ch_path)
                                    if not elapsed_str:
                                        elapsed_str = self._crosscheck_elapsed(ch_path)
                            # (C) 작업중/충전/방전/진행/휴지 → Reserve 예약 정보만 부가
                            #     서버 동기화 주기로 mtime 무의미 → 경과시간 미표시
                            elif status in ("작업중", "충전", "방전", "진행", "휴지"):
                                ch_path = self._build_channel_path(
                                    df, ch_idx, has_rpath, has_path)
                                if ch_path:
                                    reserve = self._parse_reserve_info(ch_path)
                                    if reserve:
                                        status = f"{status} ({reserve})"
                            # (D) 완료/시험완료 → 셀있음(vol!="-") 일 때만 경과시간 표시
                            #     셀없음(vol=="-") 은 회수 완료 상태 → 시간 표시 의미 없음
                            _sb_tmp = status.split(" (")[0] if " (" in status else status
                            if (status == "완료" or _sb_tmp == "시험완료") and vol != "-":
                                ch_path = self._build_channel_path(
                                    df, ch_idx, has_rpath, has_path)
                                if ch_path:
                                    elapsed_str = self._elapsed_from_log(ch_path)
                                    if not elapsed_str:
                                        elapsed_str = self._crosscheck_elapsed(ch_path)
                        floor_name = ""
                        for fn, fc in floor_cyclers:
                            if cycler_text in fc:
                                floor_name = fn
                                break
                        if floor_name not in matched_by_floor:
                            matched_by_floor[floor_name] = {}
                        if cycler_text not in matched_by_floor[floor_name]:
                            matched_by_floor[floor_name][cycler_text] = []
                        matched_by_floor[floor_name][cycler_text].append(
                            (ch_idx, testname, status, elapsed_str, cyc,
                             vol, type_str, temp_str, cell_path))
                        total_matched += 1
                        # 카운트: Reserve 접미사 제거한 base 상태 기준
                        _sb = status.split(" (")[0] if " (" in status else status
                        if _sb in ("작업중", "충전", "방전", "진행", "휴지"):
                            working_count += 1
                        # 유휴 채널 셀 유무 카운트
                        if _sb in ("완료", "준비", "작업정지"):
                            if vol == "-":
                                idle_no_cell += 1
                            else:
                                idle_has_cell += 1
            except Exception:
                continue
            self.progressBar.setValue(int(((idx + 1) / total) * 100))
            QtWidgets.QApplication.processEvents()
        # 테이블 초기화 및 리스트 출력
        self.table_reset()
        if total_matched == 0:
            self.tb_channel.setRowCount(1)
            self.tb_channel.setColumnCount(1)
            item = QtWidgets.QTableWidgetItem("검색 결과 없음")
            item.setFont(QtGui.QFont("Malgun gothic", 10))
            item.setForeground(QtGui.QColor(173, 181, 189))
            self.tb_channel.setItem(0, 0, item)
            self.tb_summary.setItem(0, 0, QtWidgets.QTableWidgetItem("0"))
            self.tb_summary.setItem(1, 0, QtWidgets.QTableWidgetItem("0"))
            return
        # 필요한 행 수 계산: 층 헤더 + 충방전기 헤더 + 데이터 행
        row_count = 0
        for floor_name in matched_by_floor:
            row_count += 1  # 층 헤더
            for cycler_text in matched_by_floor[floor_name]:
                row_count += 1  # 충방전기 헤더
                row_count += len(matched_by_floor[floor_name][cycler_text])
        # 10열: 충방전기|채널|상태|경과|Step/Cycle|전압|동작|온도|테스트명|셀경로
        num_cols = 10
        self.tb_channel.setColumnCount(num_cols)
        # 첫 호출 시 행 높이 미반영 버그 대응 (UI 초기 min=43 clamp 회피)
        # 1) 내용·구조·숨김 상태 전부 비움
        # 2) minimum 을 먼저 낮춰야 default 가 clamp 없이 적용됨
        # 3) setRowCount 로 새 행 생성 시 새 default(20) 적용
        self.tb_channel.clearContents()
        self.tb_channel.setRowCount(0)
        self.tb_channel.verticalHeader().setMinimumSectionSize(9)   # 1차: min 낮춤
        self.tb_channel.verticalHeader().setDefaultSectionSize(20)  # 2차: default 설정
        self.tb_channel.setRowCount(row_count)
        self.tb_channel.horizontalHeader().setVisible(True)
        self.tb_channel.setHorizontalHeaderLabels(
            ["충방전기", "채널", "상태", "경과", "Step/Cycle/총Cycle",
             "전압", "동작", "온도", "테스트명", "셀 경로"])
        # 열 너비: 데이터 텍스트가 안 잘리는 최소 너비 (헤더는 잘림 허용)
        # Malgun gothic 9pt 기준 + QSS padding 4px + 여유 2px
        _fixed_widths = {
            0: 70,   # 충방전기: "PNE24" (3자리 번호 + 헤더 여유)
            1: 32,   # 채널: "001"
            2: 170,  # 상태: "중단점 도달 (S201/C89)"
            3: 53,   # 경과: "3d 5h" (+20%)
            4: 134,  # Step/Cycle/총Cycle: "000/000/0000" + 헤더 가독성
            5: 44,   # 전압: "3.821"
            6: 68,   # 동작: "DisCharge"
            7: 44,   # 온도: "-10.0"
        }
        header = self.tb_channel.horizontalHeader()
        # 1) 모드 먼저 설정 (Fixed/Stretch)
        for ci in range(num_cols):
            if ci in _fixed_widths:
                header.setSectionResizeMode(
                    ci, QtWidgets.QHeaderView.ResizeMode.Interactive)
            elif ci in (8, 9):
                header.setSectionResizeMode(
                    ci, QtWidgets.QHeaderView.ResizeMode.Stretch)
            else:
                header.setSectionResizeMode(
                    ci, QtWidgets.QHeaderView.ResizeMode.ResizeToContents)
        # 2) 고정폭 열 너비 설정 (모드 설정 후에 적용)
        header.setMinimumSectionSize(18)
        for ci, w in _fixed_widths.items():
            self.tb_channel.setColumnWidth(ci, w)
        # 행 높이는 setRowCount 이전에 default 로 일괄 설정됨 (위쪽 블록 참조)
        self.tb_channel.setUpdatesEnabled(False)
        self._filter_sections = {}
        row = 0
        # 상태별 행 전체 배경색 정의 (v3: 연녹/녹/노랑/빨강 4색)
        _PAUSED_BG = QtGui.QColor(214, 155, 154)       # 빨강: 안전조건 Code + 챔버이슈
        _STOPPED_BG = QtGui.QColor(240, 220, 160)      # 노랑: 사용자멈춤, 중단점 도달, 작업멈춤(fallback)
        _COMPLETED_BG = QtGui.QColor(234, 239, 230)    # 연녹: 완료/시험완료 (셀있음)
        _IDLE_BG = QtGui.QColor(176, 203, 176)         # 녹: 대기/준비/작업정지 (셀없음)
        STATUS_BG = {
            "작업정지": _IDLE_BG,
            "대기": _IDLE_BG,
            "준비": _IDLE_BG,
            "완료": _COMPLETED_BG,
            "시험완료": _COMPLETED_BG,   # 🆕 .log 세분화 결과: 연녹 (셀있음)
            "사용자멈춤": _STOPPED_BG,
            "작업멈춤": _STOPPED_BG,     # 🆕 .log fallback (원인 불명) → 노랑
            "잠시멈춤": _STOPPED_BG,     # 작업멈춤 동일 계열 → 노랑
            "챔버이슈": _PAUSED_BG,       # 🆕 하드웨어 이슈 → 빨강
        }
        # floor_cyclers 순서를 유지하여 출력
        for floor_name, floor_cycler_list in floor_cyclers:
            if floor_name not in matched_by_floor:
                continue
            # ── 층 헤더 행 ──
            floor_row = row
            floor_item = QtWidgets.QTableWidgetItem(f"▾ {floor_name}")
            floor_item.setFont(QtGui.QFont("Malgun gothic", 10, QtGui.QFont.Weight.Bold))
            floor_item.setForeground(QtGui.QColor(255, 255, 255))
            floor_item.setBackground(QtGui.QColor(60, 84, 136))
            self.tb_channel.setItem(row, 0, floor_item)
            floor_count = sum(len(v) for v in matched_by_floor[floor_name].values())
            for col in range(1, num_cols):
                filler = QtWidgets.QTableWidgetItem(
                    f"({floor_count}건)" if col == num_cols - 1 else "")
                filler.setBackground(QtGui.QColor(60, 84, 136))
                filler.setForeground(QtGui.QColor(255, 255, 255))
                filler.setFont(QtGui.QFont("Malgun gothic", 9))
                self.tb_channel.setItem(row, col, filler)
            row += 1
            # floor_cycler_list 순서를 유지하여 충방전기별 출력
            for cycler_text in floor_cycler_list:
                if cycler_text not in matched_by_floor[floor_name]:
                    continue
                channels = matched_by_floor[floor_name][cycler_text]
                # ── 충방전기 헤더 행 (최종 업데이트 시간 포함) ──
                cycler_row = row
                mtime_label = cycler_mtime.get(cycler_text, "")
                cycler_item = QtWidgets.QTableWidgetItem(f"  ▾ {cycler_text}")
                cycler_item.setFont(QtGui.QFont("Malgun gothic", 9, QtGui.QFont.Weight.Bold))
                cycler_item.setForeground(QtGui.QColor(60, 84, 136))
                cycler_item.setBackground(QtGui.QColor(232, 236, 244))
                self.tb_channel.setItem(row, 0, cycler_item)
                for col in range(1, num_cols):
                    if col == num_cols - 1:
                        txt = f"({len(channels)}건)  업데이트: {mtime_label}" if mtime_label else f"({len(channels)}건)"
                    else:
                        txt = ""
                    filler = QtWidgets.QTableWidgetItem(txt)
                    filler.setBackground(QtGui.QColor(232, 236, 244))
                    filler.setForeground(QtGui.QColor(100, 110, 130))
                    filler.setFont(QtGui.QFont("Malgun gothic", 9))
                    self.tb_channel.setItem(row, col, filler)
                row += 1
                data_start = row
                # ── 데이터 행 ──
                for ch_no, testname, status, elapsed_str, cyc, vol, type_str, temp_str, cell_path in channels:
                    bg_color = STATUS_BG.get(status)
                    status_base = status.split(" (")[0] if " (" in status else status
                    # 유휴 상태 (완료/시험완료/대기/준비/작업정지) — vol 기반 셀있음/셀없음 override
                    # _IDLE_BG(녹)=셀없음, _COMPLETED_BG(연녹)=셀있음 로 통일
                    if bg_color in (_IDLE_BG, _COMPLETED_BG):
                        bg_color = _COMPLETED_BG if vol != "-" else _IDLE_BG
                    # STATUS_BG 미매칭 + 비정상 상태 → 3색 분기
                    if bg_color is None and status_base not in self._NORMAL_STATES:
                        if status.startswith("중단점 도달"):
                            bg_color = _STOPPED_BG   # 노랑
                        elif status_base in self.COMPLETED_LABELS:
                            bg_color = _COMPLETED_BG  # 연녹
                        elif status_base in self.HW_WARNING_LABELS:
                            bg_color = _PAUSED_BG    # 빨강 (챔버이슈 등)
                        elif status_base in self.USER_OR_ERROR_LABELS:
                            bg_color = _STOPPED_BG   # 노랑 (사용자/작업멈춤)
                        else:
                            # Code 128/129/134/142/208/209 Code_Desc 라벨 + 미정의 코드
                            bg_color = _PAUSED_BG    # 빨강 (안전조건 + fallback)
                    _font9 = QtGui.QFont("Malgun gothic", 9)
                    # col 0: 충방전기
                    item_cycler = QtWidgets.QTableWidgetItem(cycler_text)
                    item_cycler.setFont(_font9)
                    if bg_color:
                        item_cycler.setBackground(bg_color)
                    self.tb_channel.setItem(row, 0, item_cycler)
                    # col 1: 채널
                    item_ch = QtWidgets.QTableWidgetItem(str(ch_no).zfill(3))
                    item_ch.setFont(_font9)
                    if bg_color:
                        item_ch.setBackground(bg_color)
                    self.tb_channel.setItem(row, 1, item_ch)
                    # col 2: 상태
                    item_status = QtWidgets.QTableWidgetItem(status)
                    item_status.setFont(_font9)
                    if bg_color:
                        item_status.setBackground(bg_color)
                    self.tb_channel.setItem(row, 2, item_status)
                    # col 3: 경과
                    # 완료/시험완료 → 회색 (정상 방치), 그 외(멈춤류) → 빨강 (이상 경고)
                    item_elapsed = QtWidgets.QTableWidgetItem(elapsed_str)
                    item_elapsed.setFont(_font9)
                    if elapsed_str:
                        if status_base in self.COMPLETED_LABELS:
                            item_elapsed.setForeground(QtGui.QColor(100, 100, 100))
                        else:
                            item_elapsed.setForeground(QtGui.QColor(150, 80, 80))
                    if bg_color:
                        item_elapsed.setBackground(bg_color)
                    self.tb_channel.setItem(row, 3, item_elapsed)
                    # col 4: Step/Cycle
                    item_cyc = QtWidgets.QTableWidgetItem(cyc)
                    item_cyc.setFont(_font9)
                    if bg_color:
                        item_cyc.setBackground(bg_color)
                    self.tb_channel.setItem(row, 4, item_cyc)
                    # col 5: 전압
                    item_vol = QtWidgets.QTableWidgetItem(vol)
                    item_vol.setFont(_font9)
                    if bg_color:
                        item_vol.setBackground(bg_color)
                    self.tb_channel.setItem(row, 5, item_vol)
                    # col 6: 동작
                    item_type = QtWidgets.QTableWidgetItem(type_str)
                    item_type.setFont(_font9)
                    if bg_color:
                        item_type.setBackground(bg_color)
                    self.tb_channel.setItem(row, 6, item_type)
                    # col 7: 온도
                    item_temp = QtWidgets.QTableWidgetItem(temp_str)
                    item_temp.setFont(_font9)
                    if bg_color:
                        item_temp.setBackground(bg_color)
                    self.tb_channel.setItem(row, 7, item_temp)
                    # col 8: 테스트명
                    item_test = QtWidgets.QTableWidgetItem(testname)
                    item_test.setFont(_font9)
                    if bg_color:
                        item_test.setBackground(bg_color)
                    self.tb_channel.setItem(row, 8, item_test)
                    # col 9: 셀 경로
                    item_path = QtWidgets.QTableWidgetItem(cell_path)
                    item_path.setFont(QtGui.QFont("Malgun gothic", 8))
                    item_path.setForeground(QtGui.QColor(120, 120, 120))
                    if bg_color:
                        item_path.setBackground(bg_color)
                    self.tb_channel.setItem(row, 9, item_path)
                    row += 1
                # 충방전기 섹션 등록 (데이터 행 범위)
                data_rows = list(range(data_start, row))
                if data_rows:
                    self._filter_sections[cycler_row] = {
                        'rows': data_rows, 'collapsed': False, 'type': 'cycler'}
            # 층 섹션 등록 (충방전기 헤더 + 데이터 행 전체)
            floor_child_rows = list(range(floor_row + 1, row))
            if floor_child_rows:
                self._filter_sections[floor_row] = {
                    'rows': floor_child_rows, 'collapsed': False, 'type': 'floor'}
        self.tb_channel.setUpdatesEnabled(True)
        # 헤더 클릭 정렬 시그널 연결
        _hdr = self.tb_channel.horizontalHeader()
        try:
            _hdr.sectionClicked.disconnect(self._sort_filter_column)
        except (TypeError, RuntimeError):
            pass
        _hdr.sectionClicked.connect(self._sort_filter_column)
        self._filter_sort_col = -1
        self._filter_sort_asc = True
        # 요약 정보
        if is_idle_mode:
            idle_label = f"{idle_no_cell} (대기-셀없음) / {idle_has_cell} (대기-셀있음) / {total_channels} (전체)"
            self.tb_summary.setItem(0, 0, QtWidgets.QTableWidgetItem(idle_label))
            self.tb_summary.setItem(1, 0, QtWidgets.QTableWidgetItem(str(working_count)))
        else:
            self.tb_summary.setItem(0, 0, QtWidgets.QTableWidgetItem(str(total_matched)))
            self.tb_summary.setItem(1, 0, QtWidgets.QTableWidgetItem(str(working_count)))
        self.progressBar.setValue(100)

    def _sort_filter_column(self, col_idx: int):
        """현황 탭 테이블 헤더 클릭 → 충방전기 그룹 내 데이터 행 정렬"""
        if not self._filter_sections:
            return
        # 방향 토글: 같은 열 재클릭 → 반전, 다른 열 → 오름차순
        if col_idx == self._filter_sort_col:
            self._filter_sort_asc = not self._filter_sort_asc
        else:
            self._filter_sort_col = col_idx
            self._filter_sort_asc = True
        ascending = self._filter_sort_asc
        tb = self.tb_channel
        num_cols = tb.columnCount()
        tb.setUpdatesEnabled(False)
        for sec in self._filter_sections.values():
            if sec.get('type') != 'cycler' or sec.get('collapsed'):
                continue
            rows = sec['rows']
            if len(rows) < 2:
                continue
            # 각 행의 전체 셀 데이터 수집
            row_data = []
            for r in rows:
                cells = []
                for c in range(num_cols):
                    item = tb.item(r, c)
                    cells.append(item.clone() if item else None)
                sort_key = tb.item(r, col_idx)
                row_data.append((sort_key.text() if sort_key else "", cells))
            # 숫자 우선 정렬 시도
            try:
                row_data.sort(key=lambda x: float(x[0].replace(" ", "")),
                              reverse=not ascending)
            except (ValueError, AttributeError):
                row_data.sort(key=lambda x: x[0], reverse=not ascending)
            # 정렬된 순서로 재배치
            for i, (_, cells) in enumerate(row_data):
                r = rows[i]
                for c in range(num_cols):
                    if cells[c]:
                        tb.setItem(r, c, cells[c])
        tb.setUpdatesEnabled(True)

